def convert_predictions(model_output, x_t, t, alpha_bars):
    """Convert between ε, x_0, and v parameterizations."""
    ab  = alpha_bars[t].view(-1, 1, 1, 1)
    sab = ab.sqrt()
    s1m = (1 - ab).sqrt()

    # If model predicts ε:
    def from_eps(eps):
        x0  = (x_t - s1m * eps) / sab          # recover x_0
        v   = sab * eps - s1m * x0             # convert to v
        return {"x0": x0, "v": v}

    # If model predicts v:
    def from_v(v):
        x0  = sab * x_t - s1m * v              # recover x_0
        eps = s1m * x_t + sab * v              # recover ε
        return {"x0": x0, "eps": eps}

    # If model predicts x_0:
    def from_x0(x0):
        eps = (x_t - sab * x0) / s1m           # recover ε
        v   = sab * eps - s1m * x0             # convert to v
        return {"eps": eps, "v": v}

    return from_eps, from_v, from_x0
